-- ═══════════════════════════════════════════════════════════════════
-- CodeQuest · Migración 013 — SQL con Oracle · M2: Identidad y reglas de negocio
-- ═══════════════════════════════════════════════════════════════════
-- Cubre la Parte II (núcleo) del temario obligatorio: taxonomía de
-- UIDs (simple/compuesto/artificial/dependiente de relación),
-- candidatos/primario/secundarios/clave alternativa, dependencia
-- existencial, transferibilidad (y su versión condicional) y reglas
-- estructurales vs de procedimiento. Los arcos/jerarquías/subtipos de
-- la Parte II viven en m3a (modelado avanzado).
-- NO duplica la teoría formal (tupla/dominio/grado): ya vive en M1
-- ('La anatomía de una tabla').
-- Precisiones Oracle incorporadas: una FK puede referenciar PK o
-- UNIQUE compatible; UNIQUE admite múltiples nulos (se profundiza en
-- DDL); restricciones declarativas ANTES que triggers.
-- Diagrama 2.1 (UID dependiente de relación, CUENTA|BANCO) con
-- NetworkDiagram data-driven — sin frontend nuevo.
-- Reglas de contenido: quizzes autocontenidos o con términos técnicos.
-- OJO: SQL con Oracle está PUBLICADO — esta migración sale en vivo.
-- Idempotente: borra y recrea las lecciones de ESTE módulo.
-- Ejecutar DESPUÉS de 011 (estructura v2).
-- ═══════════════════════════════════════════════════════════════════

-- Limpia el módulo (cascade borra sus content_blocks)
delete from public.lessons
where module_id = (
  select m.id
  from public.modules m
  join public.courses c on c.id = m.course_id
  where c.slug = 'sql-oracle' and m.slug = 'm02-modelo-relacional'
);

-- ── Lecciones del módulo ──────────────────────────────────────────────
insert into public.lessons (module_id, slug, title, kind, xp, sort_order)
select m.id, v.slug, v.title, v.kind, v.xp, v.ord
from public.modules m
join public.courses c on c.id = m.course_id,
     (values
       ('m02-l01-taxonomia-uid',       'La taxonomía del UID',                'leccion',  20, 1),
       ('m02-l02-candidatos',          'Candidatos, primario y alternativas', 'leccion',  20, 2),
       ('m02-l03-dependencia-existencial','Dependencia existencial',          'leccion',  20, 3),
       ('m02-l04-transferibilidad',    'Transferibilidad',                    'leccion',  20, 4),
       ('m02-l05-reglas-de-negocio',   'Reglas estructurales y de procedimiento','leccion', 20, 5),
       ('m02-l06-practica-identidad',  'Práctica: la hoja de identidad',      'practica', 20, 6),
       ('m02-x01-examen',              'Examen: Identidad y reglas',          'examen',   40, 7)
     ) as v(slug, title, kind, xp, ord)
where c.slug = 'sql-oracle' and m.slug = 'm02-modelo-relacional';

-- ═════════════════════════════════════════════════════════════════════
-- L01 · La taxonomía del UID
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El ADN de la identidad","body":"En el módulo 1 marcaste el UID con # en el cuadro editable. Este módulo lo disecciona, porque el UID (identificador único) es el pilar de la integridad: el atributo — o combinación de atributos — que distingue INEQUÍVOCAMENTE una instancia de todas las demás. Sin un UID sólido, el sistema colapsa en ambigüedad: ¿cuál de los tres 'Luis Vega' es el paciente de la cita? La taxonomía completa tiene cuatro especies. UID SIMPLE: un solo atributo basta (historia_clinica en PACIENTE). UID COMPUESTO: se necesita la combinación de varios — en una entrada de concierto, ni el asiento ni la fecha identifican solos; asiento + fecha de función, sí. Las otras dos especies — artificial y dependiente de relación — merecen bloque propio."}$j$),
  (2, 'texto', $j${"title":"El UID artificial: inventado a propósito","body":"A veces ningún atributo natural sirve como identificador: los nombres se repiten, los datos naturales cambian o son sensibles. La solución del oficio es el UID ARTIFICIAL: un atributo que NO existe en el mundo real, creado exclusivamente para identificar — el número de alumno, el número de empleado, el cita_id del hospital. No describe nada de la instancia; solo la nombra. Su gran virtud es la ESTABILIDAD: como no significa nada, nada del mundo real lo obliga a cambiar (recuerda el criterio volátil/no volátil del módulo 1: el UID debe ser lo MENOS volátil de la entidad). En el modelo físico, los UID artificiales suelen alimentarse con secuencias de Oracle — las conocerás en el módulo de DDL, con una advertencia curiosa: pueden dejar huecos en la numeración, y no pasa nada."}$j$),
  (3, 'texto', $j${"title":"El UID dependiente de relación: la barra","body":"La cuarta especie es la más sutil. A veces una instancia NO puede identificarse sin mencionar a otra entidad: el número de cuenta 001-2044 no identifica nada por sí solo, porque DOS BANCOS distintos pueden usar la misma numeración interna — la cuenta solo queda identificada como 'la 001-2044 DEL Banco Andino'. Eso es un UID DEPENDIENTE DE RELACIÓN: el identificador incluye la relación con la otra entidad, y en el ERD se marca dibujando una BARRA (|) cruzando la línea de esa relación. Es un patrón cotidiano: el número de habitación depende del hotel, el número de asiento depende de la sala. Atención a un matiz que reaparecerá en el modelado avanzado: esta barra (relación identificadora) NO es lo mismo que un arco — la barra dice 'te necesito para EXISTIR con nombre'; el arco dirá 'elijo a uno de ustedes'."}$j$),
  (4, 'diagrama', $j${"title":"Diagrama 2.1 · El UID que necesita a otro","component":"NetworkDiagram","props":{"label":"UID dependiente de relación: CUENTA necesita a BANCO","ancho":520,"alto":300,"grupos":[{"id":"cuenta","x":260,"y":40,"w":240,"h":230,"titulo":"CUENTA","descripcion":"La entidad cuyo UID está incompleto por sí solo: su número interno se repite entre bancos."}],"nodos":[{"id":"banco","x":24,"y":120,"w":170,"h":52,"titulo":"BANCO","subtitulo":"# banco_id · * nombre","descripcion":"La entidad de la que depende la identidad de CUENTA. Un banco tiene muchas cuentas (1:N)."},{"id":"num","x":284,"y":76,"w":192,"h":40,"titulo":"# numero_cuenta","tag":"parcial","descripcion":"Parte del UID… pero insuficiente: el Banco Andino y el Banco del Sur pueden tener ambos una cuenta 001-2044."},{"id":"rel","x":284,"y":132,"w":192,"h":40,"titulo":"| banco (relación)","tag":"la barra","descripcion":"La BARRA (|): la relación con BANCO forma parte del UID. La cuenta queda identificada como numero_cuenta + banco. En el físico, esta barra se convertirá en una FK que entra a la PK — el módulo de mapeo lo hará contigo."},{"id":"saldo","x":284,"y":188,"w":192,"h":40,"titulo":"* saldo","descripcion":"Atributo obligatorio normal: describe, no identifica."}],"enlaces":[{"de":"banco","a":"rel","tipo":"flecha","etiqueta":"1:N","descripcion":"Un banco tiene muchas cuentas; cada cuenta pertenece a exactamente un banco — y lo necesita para tener identidad completa."}],"hint":"Toca cada elemento: la barra es la protagonista."},"caption":"UID de CUENTA = numero_cuenta + la relación con BANCO. La barra en el ERD anuncia lo que el físico cumplirá: una FK dentro de la PK."}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"En una entrada de concierto, ni el número de asiento ni la fecha de función identifican solos a la entrada, pero su combinación sí. ¿Qué tipo de UID es?","options":["Simple, de un solo atributo","Artificial, creado por el sistema","Compuesto: surge de combinar varios atributos","No es un identificador válido de ningún tipo"],"correctIndex":2,"feedback":{"correct":"Correcto. Asiento 14 hay en todas las funciones; función del viernes tiene cientos de asientos; asiento 14 + función del viernes es UNA entrada.","incorrect":"Cuando ningún atributo identifica solo pero la combinación sí, el UID es COMPUESTO."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"El número de empleado no existe en el mundo natural: la empresa lo inventó solo para identificar. En términos de taxonomía de UIDs es un UID…","options":["Compuesto, hecho de varios atributos juntos","Dependiente de otra relación","Volátil, cambia con el tiempo","Artificial: creado por el sistema, sin significado"],"correctIndex":3,"feedback":{"correct":"Correcto. No describe nada: solo nombra. Su falta de significado es su superpoder — nada lo obliga a cambiar.","incorrect":"Un identificador inventado para el sistema (número de alumno, de empleado, cita_id) es un UID ARTIFICIAL."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"Dos bancos pueden usar internamente el mismo número de cuenta. Para que CUENTA quede bien identificada, su UID debe…","options":["Incluir la relación con BANCO (UID dependiente)","Cambiar el número de cuenta por uno más largo","Eliminar por completo la entidad BANCO","Usar el saldo de la cuenta como identificador"],"correctIndex":0,"feedback":{"correct":"Correcto. numero_cuenta + banco: la identidad completa exige la relación — la barra del ERD.","incorrect":"El número se repite entre bancos: la identidad necesita la relación. Ese es el UID dependiente de relación (la barra |)."}}$j$),
  (8, 'resumen', $j${"title":"Resumen — La taxonomía del UID","points":["El UID distingue inequívocamente cada instancia: el pilar de la integridad.","SIMPLE: un atributo basta. COMPUESTO: identifica la combinación.","ARTIFICIAL: inventado para el sistema (número de empleado) — estable porque no significa nada.","DEPENDIENTE DE RELACIÓN: la identidad incluye a otra entidad; se marca con la barra (|).","La barra (relación identificadora) NO es un arco: 'te necesito para existir' ≠ 'elijo a uno de ustedes'."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm02-l01-taxonomia-uid';

-- ═════════════════════════════════════════════════════════════════════
-- L02 · Candidatos, primario y alternativas
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Cuando hay varios aspirantes","body":"Es común que una entidad tenga VARIOS identificadores posibles: un EMPLEADO se distingue por su número de empleado, por su RFC y quizá por su correo corporativo. Cada aspirante es un UID CANDIDATO. El arquitecto debe elegir UNO como UID PRIMARIO — el identificador oficial — y los demás quedan como UIDs SECUNDARIOS (también llamados CLAVES ALTERNATIVAS: siguen siendo únicos, pero no gobiernan). Los criterios de elección son los del módulo 1 aplicados con rigor: ESTABILIDAD ante todo (el menos volátil gana: el correo cambia, el RFC puede corregirse; el número de empleado, jamás), brevedad, y una consideración moderna — la PRIVACIDAD: usar un dato sensible como el RFC de identificador lo esparce por todo el sistema. Por eso, en la práctica, el artificial casi siempre gana el puesto de primario."}$j$),
  (2, 'texto', $j${"title":"Lo que el físico hará con cada uno","body":"Adelanto del mapeo (módulo 'Del modelo al esquema Oracle'), porque da sentido a la elección: el UID PRIMARIO se convertirá en la CLAVE PRIMARIA (PRIMARY KEY) de la tabla — única y NO NULA, sin excepciones. Los UIDs SECUNDARIOS se convertirán en restricciones UNIQUE: Oracle seguirá garantizando que no se repitan, aunque no gobiernen la tabla. Dos precisiones de Oracle que las entrevistas adoran: una UNIQUE admite filas con NULO (varias, de hecho — el nulo no se compara como un valor), cosa que la PK jamás permite; y una FOREIGN KEY puede referenciar no solo a la PK, sino también a una UNIQUE compatible — aunque la práctica estándar es apuntar a la PK. Todo esto se materializa en el módulo de DDL; aquí basta con que la decisión lógica (primario vs secundarios) ya sepa a dónde va."}$j$),
  (3, 'ejemplo_sql', $j${"title":"Candidatos y alternativas, vistos en el esquema","code":"-- Adelanto del físico: así aterrizan primario y secundarios\nCREATE TABLE empleado (\n  empleado_id  NUMBER       CONSTRAINT epe_pk PRIMARY KEY,  -- UID primario\n  rfc          VARCHAR2(13) CONSTRAINT epe_rfc_uk UNIQUE,   -- secundario\n  correo       VARCHAR2(80) CONSTRAINT epe_correo_uk UNIQUE,-- secundario\n  nombre       VARCHAR2(60) NOT NULL\n);","result":{"columns":["RESULTADO"],"rows":[["Table EMPLEADO created."]],"note":"La PK es única y NO nula. Las UNIQUE también impiden duplicados… pero admiten nulos: un empleado sin correo registrado no viola epe_correo_uk."},"caption":"El modelo lógico decide (primario vs secundarios); el físico obedece (PRIMARY KEY vs UNIQUE). La sintaxis completa de constraints llega en el módulo de DDL."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"EMPLEADO tiene tres identificadores posibles: número de empleado, RFC y correo corporativo. En la terminología del oficio, los tres son UIDs…","options":["Claves primarias definitivas","Candidatos: de ellos se elige uno como primario","Identificadores artificiales del sistema","Atributos compuestos de la entidad"],"correctIndex":1,"feedback":{"correct":"Correcto. Candidatos → se corona un primario → el resto son secundarios/alternativas (únicos, pero sin gobernar).","incorrect":"Varios aspirantes = UIDs candidatos. El arquitecto elige el primario; los demás quedan como claves alternativas."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Entre el correo corporativo (cambia al casarse o al renombrar dominios), el RFC (dato fiscal sensible) y el número de empleado (artificial), ¿cuál conviene como UID primario y por qué?","options":["El correo, porque casi todos lo recuerdan bien","El RFC, porque es un dato oficial","El número de empleado: es el más estable y neutro","Cualquiera de ellos da exactamente igual"],"correctIndex":2,"feedback":{"correct":"Correcto. Estabilidad + privacidad: el artificial gana casi siempre. El RFC y el correo quedan como alternativas UNIQUE.","incorrect":"El criterio es estabilidad (mínima volatilidad) y no esparcir datos sensibles: el artificial es el campeón habitual."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión Oracle: ¿cuál es la diferencia clave entre PRIMARY KEY y UNIQUE en cuanto a valores nulos?","options":["Ninguna: las dos prohíben los nulos","La UNIQUE prohíbe nulos y la PK los permite","Las dos admiten un único valor nulo","La PK nunca admite nulos; una UNIQUE sí los admite"],"correctIndex":3,"feedback":{"correct":"Correcto. El nulo no se compara como un valor: la UNIQUE lo tolera; la PK, jamás. Detalle de entrevista — y de diseño.","incorrect":"PK = única + no nula, siempre. UNIQUE = sin duplicados, pero con nulos permitidos (el nulo no es un valor comparable)."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Candidatos y alternativas","points":["Varios identificadores posibles = UIDs CANDIDATOS; se elige UN primario y el resto son secundarios (claves alternativas).","Criterios: estabilidad (mínima volatilidad), brevedad y privacidad — el artificial casi siempre gana.","En el físico: primario → PRIMARY KEY (única y no nula); secundarios → UNIQUE.","Precisión Oracle: UNIQUE admite nulos (varios); la PK jamás.","Precisión Oracle: una FK puede referenciar una PK o una UNIQUE compatible — la práctica estándar apunta a la PK."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm02-l02-candidatos';

-- ═════════════════════════════════════════════════════════════════════
-- L03 · Dependencia existencial
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Entidades que no viven solas","body":"Algunas entidades tienen vida propia: un MEDICO existe aunque hoy no tenga citas. Otras NO pueden existir sin su entidad madre: una CITA sin paciente no es una cita — es un renglón sin sentido. Esa es la DEPENDENCIA EXISTENCIAL: la instancia de una entidad requiere obligatoriamente la existencia de una instancia de la otra. En el ERD ya sabes leerla: es la participación total del módulo 1 (el lado obligatorio de la relación), y suele venir acompañada de la barra del UID dependiente cuando además la identidad se hereda. Al dúo se le llama entidad FUERTE (independiente) y entidad DÉBIL (dependiente). El detalle profesional: la dependencia existencial es una REGLA DE NEGOCIO que el modelo captura — y que el físico va a hacer cumplir con NOT NULL en la FK y decisiones de borrado (¿si borro al paciente, qué pasa con sus citas?) que el módulo de DDL pondrá sobre la mesa."}$j$),
  (2, 'quiz', $j${"variant":"multiple_choice","prompt":"Una CITA no puede existir sin su PACIENTE, pero un PACIENTE existe aunque nunca haya tenido citas. En términos técnicos, CITA es la entidad…","options":["Débil: depende de la existencia de PACIENTE","Fuerte, con existencia independiente","Artificial, creada para el sistema","Transitiva a través de otra entidad"],"correctIndex":0,"feedback":{"correct":"Correcto. CITA depende existencialmente de PACIENTE: participación total del lado de la cita.","incorrect":"La que no puede existir sin la otra es la DÉBIL (dependiente): CITA necesita a PACIENTE, no al revés."}}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"En el modelo físico, ¿cómo se hace cumplir la dependencia existencial de CITA respecto a PACIENTE?","options":["Con un comentario dentro del código","Con la FK de cita a paciente marcada NOT NULL","Borrando por completo la tabla PACIENTE","Con un índice sobre esa columna"],"correctIndex":1,"feedback":{"correct":"Correcto. FK + NOT NULL: la regla lógica convertida en muro físico. Las opciones de borrado en cascada llegan en DDL.","incorrect":"La dependencia existencial aterriza como FK NOT NULL: ninguna cita puede existir sin apuntar a un paciente real."}}$j$),
  (4, 'resumen', $j${"title":"Resumen — Dependencia existencial","points":["Entidad FUERTE: existe sola (MEDICO). Entidad DÉBIL: requiere a su madre (CITA sin PACIENTE no es nada).","La dependencia existencial se lee en el ERD como participación total del lado dependiente.","Cuando además la identidad se hereda, se suma la barra del UID dependiente de relación.","En el físico: FK con NOT NULL — y decisiones de borrado que el módulo de DDL abordará.","Es una regla de negocio capturada por el modelo: el sistema la hará cumplir sola."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm02-l03-dependencia-existencial';

-- ═════════════════════════════════════════════════════════════════════
-- L04 · Transferibilidad
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"¿Esta conexión puede cambiar de manos?","body":"Ya sabes preguntar cuántos (cardinalidad) y si es obligatorio (opcionalidad). La tercera pregunta del oficio: ¿la relación puede CAMBIAR una vez creada? Una relación TRANSFERIBLE admite reasignación: la CITA que atendía el Dr. Reyes puede transferirse a la Dra. Solís si él enferma — la conexión cita–médico cambia de manos sin drama. Una relación NO TRANSFERIBLE queda sellada al nacer: un POEMA no puede cambiar de AUTOR — reasignarlo no es corregir, es falsificar la historia. En el ERD, la no transferibilidad se marca con un ROMBO sobre la línea de la relación. Y existe el punto medio: la NO TRANSFERIBILIDAD CONDICIONAL, donde la posibilidad de transferir depende del TIEMPO o del estado — el turno de un voluntario puede reasignarse a otro voluntario… solo mientras el turno no haya comenzado. Esa versión condicionada reaparecerá en el modelado temporal."}$j$),
  (2, 'quiz', $j${"variant":"multiple_choice","prompt":"Un POEMA no puede cambiar de AUTOR una vez registrado. En el ERD, esa regla se llama y se dibuja…","options":["Cardinalidad, con pata de gallo","Opcionalidad, con línea discontinua","No transferibilidad, marcada con un rombo","Dependencia, marcada con una barra"],"correctIndex":2,"feedback":{"correct":"Correcto. El rombo sella la conexión: reasignar un poema no es corregir, es falsificar.","incorrect":"La relación que no puede cambiar de manos es NO TRANSFERIBLE y su marca en el ERD es el rombo."}}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"El turno de un voluntario puede reasignarse a otro voluntario SOLO mientras el turno no haya comenzado. Esa regla es…","options":["Una transferibilidad total, libre y sin límites","Una cardinalidad de tipo N:M","Un UID compuesto de varios campos","No transferibilidad condicional: depende del estado"],"correctIndex":3,"feedback":{"correct":"Correcto. Ni sellada ni libre: condicionada. El modelado temporal la retomará con herramientas de fechas.","incorrect":"Cuando el 'se puede transferir' depende del tiempo/estado, es no transferibilidad CONDICIONAL."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"En el hospital: la CITA aún no atendida puede reasignarse de médico; una vez ATENDIDA, jamás (el acto médico ya ocurrió). Clasifica la relación CITA–MEDICO:","options":["No transferible condicional: solo hasta que se atiende","Transferible siempre, sin ninguna condición previa","No transferible ya desde el inicio","Sin ninguna relación entre ellas"],"correctIndex":0,"feedback":{"correct":"Correcto. El estado 'atendida' sella la conexión: historia clínica no se reescribe. Regla de negocio pura capturada por el modelo.","incorrect":"Depende del estado: antes de atenderse, transferible; después, sellada. Eso es no transferibilidad condicional."}}$j$),
  (5, 'resumen', $j${"title":"Resumen — Transferibilidad","points":["Tercera pregunta del oficio: ¿la relación puede cambiar de manos una vez creada?","TRANSFERIBLE: se reasigna sin drama (la cita pendiente cambia de médico).","NO TRANSFERIBLE: sellada al nacer — se marca con un ROMBO en el ERD (POEMA–AUTOR).","CONDICIONAL: transferible según tiempo o estado (el turno antes de comenzar; la cita antes de atenderse).","La versión condicionada por el tiempo reaparece en el modelado temporal (módulo 4)."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm02-l04-transferibilidad';

-- ═════════════════════════════════════════════════════════════════════
-- L05 · Reglas estructurales y de procedimiento
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Dos familias de reglas de negocio","body":"Todo lo que has marcado en el ERD — cardinalidades, opcionalidad, barras, rombos — son REGLAS DE NEGOCIO capturadas gráficamente. La clasificación del oficio distingue dos familias. Las REGLAS ESTRUCTURALES definen QUÉ estados de los datos son válidos, y SE DIBUJAN en el modelo: 'todo paciente tiene exactamente un expediente' (cardinalidad 1:1), 'una cita pertenece obligatoriamente a un paciente' (participación total), 'el poema no cambia de autor' (rombo). Las REGLAS DE PROCEDIMIENTO definen FLUJOS de trabajo — secuencias, aprobaciones, validaciones cruzadas: 'el gerente debe aprobar el viaje ANTES de comprarse el boleto', 'la cita se factura solo después de atenderse'. Estas NO caben en el ERD: requieren programación adicional."}$j$),
  (2, 'texto', $j${"title":"Dónde vive cada regla (y la jerarquía de herramientas)","body":"La pregunta de arquitecto: ¿con qué herramienta hago cumplir cada regla? La escalera, del cimiento hacia arriba: (1) RESTRICCIONES DECLARATIVAS — NOT NULL, PRIMARY KEY, FOREIGN KEY, UNIQUE, CHECK: viven en la base de datos, se declaran una vez y NADIE puede saltárselas, entre por donde entre el dato. (2) TRIGGERS — código PL/SQL que se dispara ante cambios: potente, para reglas que las declarativas no alcanzan… y más difícil de mantener y depurar. (3) LÓGICA DE APLICACIÓN — el código del sistema: flexible, pero cada aplicación nueva debe re-implementarla (y alguien la olvidará). La regla de oro del oficio, grábatela: PRIORIZA LO DECLARATIVO — usa triggers solo cuando una CHECK no alcanza, y lógica de aplicación solo para lo que ni siquiera un trigger expresa bien. Cuanto más abajo vive la regla, más difícil es violarla."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"'Toda cita pertenece obligatoriamente a un paciente' y 'el gerente debe aprobar el viaje antes de comprar el boleto'. Clasifica ambas reglas:","options":["Las dos son reglas estructurales","La primera es estructural (ERD); la segunda de procedimiento","Las dos son reglas de procedimiento","La primera es de procedimiento y la segunda estructural"],"correctIndex":1,"feedback":{"correct":"Correcto. Estados válidos de los datos → estructural (ERD). Flujos y aprobaciones → procedimiento (código).","incorrect":"Lo que define estados válidos se dibuja (estructural); lo que define flujos de trabajo se programa (procedimiento)."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Según la jerarquía profesional de herramientas, ¿en qué orden se prefiere implementar una regla de negocio?","options":["Lógica de aplicación, luego triggers, luego declarativas","Los triggers deben ir siempre en primer lugar","Declarativas primero; triggers si no alcanzan; app al final","El orden entre ellas es del todo indiferente"],"correctIndex":2,"feedback":{"correct":"Correcto. Cuanto más abajo vive la regla (más cerca de los datos), más difícil violarla. Declarativo primero, siempre.","incorrect":"La escalera del oficio: declarativas → triggers → aplicación. La regla que vive en la base no se puede esquivar."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué una regla implementada SOLO en la lógica de aplicación es la más frágil de la escalera?","options":["Porque el código de aplicación es muy lento","Porque las aplicaciones por sí solas no pueden validar","Porque Oracle acaba borrando esa regla","Cada aplicación debe reimplementarla y alguna la olvidará"],"correctIndex":3,"feedback":{"correct":"Correcto. La base recibe datos de muchos caminos; solo las reglas que viven EN la base los cubren todos.","incorrect":"La regla en la app protege solo ESA app: otro sistema, un script o una carga masiva entran sin el filtro. Por eso: declarativo primero."}}$j$),
  (6, 'resumen', $j${"title":"Resumen — Reglas de negocio","points":["ESTRUCTURALES: estados válidos de los datos — se dibujan en el ERD (cardinalidad, opcionalidad, rombo, barra).","DE PROCEDIMIENTO: flujos y aprobaciones — no caben en el ERD; se programan.","La escalera de implementación: restricciones DECLARATIVAS → triggers → lógica de aplicación.","Prioriza lo declarativo: la regla que vive en la base no se puede esquivar.","Triggers y PL/SQL tienen módulo propio al final del curso; las declarativas, en DDL."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm02-l05-reglas-de-negocio';

-- ═════════════════════════════════════════════════════════════════════
-- L06 · Práctica: la hoja de identidad (kind = practica)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'ejercicio', $j${"scenario":"El hospital está formalizando la identidad de sus entidades y te pasó la hoja de decisiones a medio llenar. El caso 1 viene resuelto de ejemplo; completa los demás reemplazando cada ? con tu decisión de arquitecto.","instructions":["Caso 2 — MEDICO tiene tres candidatos: colegiatura (estable, pública en su gafete), rfc (dato fiscal sensible) y correo (cambia con los años). Elige el UID primario.","Caso 3 — CITA se identifica por cita_id, generado por el sistema sin significado real. Clasifica su tipo de UID: simple, compuesto, artificial o dependiente.","Caso 4 — HABITACION: el número 204 existe en el ala norte Y en el ala sur; solo 'la 204 DEL ala norte' identifica. Clasifica su UID.","Caso 5 — 'La cita facturada no puede cambiar de paciente': clasifica la regla como estructural o procedimiento (pista: ¿se dibuja en el ERD — rombo condicional — o exige flujo programado?)."],"initialCode":"-- HOJA DE IDENTIDAD — Hospital San Rafael\n\n-- Caso 1 (ejemplo): PACIENTE\n--   candidatos: dni, historia_clinica, correo\ncaso1_uid_primario=historia_clinica\n\n-- Caso 2: MEDICO — candidatos: colegiatura, rfc, correo\ncaso2_uid_primario=?\n\n-- Caso 3: CITA — cita_id generado por el sistema\n--   (simple / compuesto / artificial / dependiente)\ncaso3_tipo_uid=?\n\n-- Caso 4: HABITACION — numero + su relación con ALA\n--   (simple / compuesto / artificial / dependiente)\ncaso4_tipo_uid=?\n\n-- Caso 5: 'la cita facturada no cambia de paciente'\n--   (estructural / procedimiento)\ncaso5_tipo_regla=?","validators":["caso2_uid_primario\\s*=\\s*colegiatura\\b","caso3_tipo_uid\\s*=\\s*artificial\\b","caso4_tipo_uid\\s*=\\s*dependiente\\b","caso5_tipo_regla\\s*=\\s*estructural\\b"],"mockOutput":{"columns":["CASO","DECISIÓN","POR QUÉ"],"rows":[["1 · PACIENTE","historia_clinica","estable y no sensible (el dni queda de alternativa UNIQUE)"],["2 · MEDICO","colegiatura","estable y no sensible; rfc es dato fiscal, correo es volátil"],["3 · CITA","artificial","generado por el sistema, sin significado: nada lo obliga a cambiar"],["4 · HABITACION","dependiente","el número se repite entre alas: la relación entra al UID (la barra |)"],["5 · regla","estructural","estado válido de los datos: rombo condicional en el ERD, no un flujo"]],"note":"La hoja completa: identidad decidida con criterio de estabilidad, privacidad y estructura."},"hints":["Caso 2: el criterio es estabilidad + privacidad — descarta lo volátil (correo) y lo sensible (rfc).","Casos 3 y 4: 'inventado por el sistema' = artificial; 'necesita a otra entidad para identificarse' = dependiente.","Caso 5: si la regla define un ESTADO válido de los datos (y se puede dibujar con un rombo condicional), es estructural; los flujos con pasos y aprobaciones son de procedimiento."],"successMessage":"Hoja de identidad entregada: elegiste primarios con criterio, clasificaste las cuatro especies de UID y separaste las familias de reglas. Estas decisiones son exactamente las que el mapeo físico convertirá en PRIMARY KEY, UNIQUE y CHECK.","failMessage":"Revisa: caso2=colegiatura (estable y no sensible) · caso3=artificial (inventado por el sistema) · caso4=dependiente (la relación entra al UID) · caso5=estructural (estado válido, se dibuja)."}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm02-l06-practica-identidad';

-- ═════════════════════════════════════════════════════════════════════
-- X01 · Examen de región (jefe del módulo)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La segunda región","body":"Byte llegó a la región de la identidad: once preguntas guardan el paso. Todo lo viviste: las cuatro especies de UID, la corona del primario y sus alternativas, las entidades que no viven solas, el rombo que sella relaciones y las dos familias de reglas. Las preguntas que falles volverán al final hasta que las domines. Adelante."}$j$),
  (2, 'quiz', $j${"variant":"multiple_choice","prompt":"El UID de una entidad es, por definición…","options":["El atributo o combinación que distingue cada instancia","El atributo más largo de toda la entidad completa","Siempre su primera columna","Siempre tiene que ser un número"],"correctIndex":0,"feedback":{"correct":"Correcto. El pilar de la integridad: sin UID sólido, ambigüedad y colapso.","incorrect":"UID = identidad inequívoca por instancia. Puede ser un atributo o una combinación — pero siempre distingue sin ambigüedad."}}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"Número de asiento + fecha de función identifican una entrada; el número de alumno fue inventado por la universidad. Sus tipos de UID son, respectivamente…","options":["Los dos son de tipo simple","Compuesto (la combinación identifica) y artificial","Artificial y dependiente de una relación externa","Los dos son identificadores simples"],"correctIndex":1,"feedback":{"correct":"Correcto. La combinación que identifica = compuesto; el inventado sin significado real = artificial.","incorrect":"Asiento+fecha = UID compuesto. Número de alumno = UID artificial (no existe en el mundo natural)."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"En un ERD ves una BARRA (|) cruzando la relación CUENTA–BANCO. La lectura correcta es…","options":["La relación entre ambas tablas está prohibida","BANCO no puede llegar a tener cuentas","El UID de CUENTA incluye la relación con BANCO","Es solo un adorno de estilo del ERD"],"correctIndex":2,"feedback":{"correct":"Correcto. Dos bancos pueden repetir numeración: la identidad completa exige la relación. En el físico: FK dentro de la PK.","incorrect":"La barra marca el UID dependiente de relación: la identidad de CUENTA necesita a BANCO."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"De los UIDs candidatos de una entidad, el primario se elige por…","options":["Por orden alfabético del atributo","El que tenga más letras que los demás","Una votación del equipo de diseño","Estabilidad, brevedad y privacidad del dato"],"correctIndex":3,"feedback":{"correct":"Correcto. El identificador oficial debe ser lo menos volátil de la entidad — y no esparcir datos sensibles.","incorrect":"Criterios del oficio: estable, breve, no sensible. Por eso los artificiales (sin significado que cambie) suelen coronarse."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Los UIDs candidatos NO elegidos como primario…","options":["Quedan como UIDs secundarios (UNIQUE en el físico)","Se eliminan por completo del modelo","Se vuelven atributos opcionales de la tabla","Pasan a formar parte de otra entidad"],"correctIndex":0,"feedback":{"correct":"Correcto. Siguen siendo únicos aunque no gobiernen: Oracle los protege con UNIQUE.","incorrect":"Los candidatos no coronados son claves alternativas: únicas (UNIQUE en el físico), pero sin gobernar la tabla."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión Oracle de entrevista: sobre nulos y unicidad, la diferencia entre PRIMARY KEY y UNIQUE es…","options":["No hay ninguna diferencia real entre las dos","La PK no admite nulos; la UNIQUE sí admite varios","La UNIQUE es más estricta que la PK","Las dos admiten un solo valor nulo"],"correctIndex":1,"feedback":{"correct":"Correcto. El nulo no se compara como valor: la UNIQUE lo tolera. Y bonus: una FK puede referenciar una PK o una UNIQUE compatible.","incorrect":"PK: única + no nula, siempre. UNIQUE: sin duplicados, nulos permitidos. Y las FK pueden apuntar a cualquiera de las dos."}}$j$),
  (8, 'quiz', $j${"variant":"multiple_choice","prompt":"Una ORDEN DE COMPRA no puede existir sin su PROVEEDOR. En el vocabulario del modelado, ORDEN DE COMPRA tiene __________ respecto a PROVEEDOR.","options":["La cardinalidad máxima de toda la relación","La transferibilidad de la relación","Dependencia existencial (en físico: FK NOT NULL)","La presencia de un arco exclusivo"],"correctIndex":2,"feedback":{"correct":"Correcto. Sin proveedor no hay orden: dependencia existencial, participación total del lado débil.","incorrect":"La entidad que necesita a otra para existir tiene dependencia existencial — y su FK nacerá NOT NULL."}}$j$),
  (9, 'quiz', $j${"variant":"multiple_choice","prompt":"El ROMBO sobre la línea de una relación en el ERD significa…","options":["Una relación de muchos a muchos","Una relación de tipo opcional","Un UID compuesto de varios campos de la entidad","No transferibilidad: la conexión no cambia de manos"],"correctIndex":3,"feedback":{"correct":"Correcto. El rombo sella: reasignar sería falsificar la historia.","incorrect":"El rombo marca la relación NO transferible: creada una vez, sellada para siempre."}}$j$),
  (10, 'quiz', $j${"variant":"multiple_choice","prompt":"'El expediente se archiva SOLO después de que el médico firma el alta' define…","options":["Una regla de procedimiento: es un flujo, se programa","Una regla estructural: se dibuja con cardinalidad","Un identificador de tipo artificial","Una clave alternativa de la entidad"],"correctIndex":0,"feedback":{"correct":"Correcto. Secuencia + aprobación = flujo = procedimiento. El ERD captura estados, no pasos.","incorrect":"Los flujos con 'antes/después' y aprobaciones son reglas de procedimiento: requieren programación (trigger o aplicación)."}}$j$),
  (11, 'quiz', $j${"variant":"multiple_choice","prompt":"Para hacer cumplir 'toda cita apunta a un paciente válido', la jerarquía profesional dicta implementarla con…","options":["Un aviso en el manual del usuario","La restricción declarativa (FK + NOT NULL) en la base","Un trigger bastante complejo dentro de la tabla","Un correo de recordatorio al equipo"],"correctIndex":1,"feedback":{"correct":"Correcto. Prioriza lo declarativo: la regla que vive en la base cubre TODOS los caminos de entrada.","incorrect":"La escalera: declarativas primero (FK NOT NULL aquí), triggers solo si no alcanzan, aplicación al final."}}$j$),
  (12, 'quiz', $j${"variant":"multiple_choice","prompt":"Pregunta final de entrevista: 'si el RFC ya identifica a cada empleado, ¿para qué inventar un empleado_id artificial?' Tu respuesta senior:","options":["Por pura tradición de la industria","Porque el RFC resulta demasiado corto","Por estabilidad, privacidad y control de la numeración","No hay ninguna razón real: es un error muy común"],"correctIndex":2,"feedback":{"correct":"Impecable. Estabilidad + privacidad + control — y nada se pierde: el RFC sigue único como alternativa. Así se defiende un diseño en una entrevista.","incorrect":"La respuesta senior: el artificial es inmune a los cambios del mundo, no esparce datos sensibles por las FK del sistema, y el RFC no desaparece — queda como clave alternativa UNIQUE."}}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm02-x01-examen';
